protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Cosmos DB indexing is managed via the container's indexing policy, not EF Core.
    // HasIndex was removed — it now throws InvalidOperationException at startup.

    // Preserve the legacy discriminator property name (EF9 defaults to "$type").
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve the legacy compound id format "Blog|1" (EF9 defaults to key-only).
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
}

